template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return a==b; }

template <>
inline half2 conv_int(const int i) { 
    half2 h;
    h.x = static_cast<float>(i);
    h.y = static_cast<float>(i);
    return h;
}

template <>
inline half2 mad(const half2 a, const half2 b, const half2 c) { 
    half2 res;
    res.x = a.x * b.x + c.x;
    res.y = a.y * b.y + c.y;
    return res;
}

template <>
inline bool equal(const half2 a, const half2 b) { 
    return (a.x == b.x) && (a.y == b.y); 
}

template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func(T seed, T *g_data, long total_elements, int num_threads) {
    const int stride = num_threads * granularity;
    const long big_stride = (long)num_threads * granularity * fusion_degree;

    #pragma omp parallel for
    for (int tid = 0; tid < num_threads; ++tid) {
        T tmps[granularity];
        long base_idx = (long)tid * granularity;

        for(int k=0; k<fusion_degree; k++){
            long offset = base_idx + (long)k * big_stride;

            for(int j=0; j<granularity; j++){
                long idx = offset + (long)j * num_threads;
                if (idx < total_elements) {
                    tmps[j] = g_data[idx];
                } else {
                    tmps[j] = conv_int<T>(0);
                }

                int iter_limit = TemperateUnroll ? 4 : 128;
                if (compute_iterations < iter_limit) iter_limit = compute_iterations;

                for(int i=0; i<compute_iterations; i++){
                    tmps[j] = mad(tmps[j], tmps[j], seed);
                }
            }

            T sum = conv_int<T>(0);
            for(int j=0; j<granularity; j+=2) {
                if (j+1 < granularity)
                    sum = mad(tmps[j], tmps[j+1], sum);
                else
                    sum = mad(tmps[j], conv_int<T>(0), sum);
            }

            if( equal(sum, conv_int<T>(-1)) ) {
                long write_idx = base_idx + (long)k * big_stride;
                if (write_idx < total_elements)
                    g_data[write_idx] = sum;
            }
        }
    }
}

double get_time() {
    return omp_get_wtime();
}

void runbench_warmup(double *cd, long size){
    const long reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
    const int TOTAL_REDUCED_BLOCKS = (int)(reduced_grid_size / ELEMENTS_PER_THREAD); // Approximate thread count logic
    int num_threads = omp_get_max_threads();
    if (TOTAL_REDUCED_BLOCKS > 0 && num_threads > TOTAL_REDUCED_BLOCKS) num_threads = TOTAL_REDUCED_BLOCKS;
    if (num_threads < 1) num_threads = 1;

    benchmark_func< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true >((short)1, (short*)cd, size, num_threads);
}

